INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-de09bf8b-moex-00069', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲持槍向乙宅開槍射擊欲射殺乙，因乙事先走避未遭殺害，但射擊當下屋內有竊賊丙，丙幸未被 射中。下列敘述何者正確？', '["甲的行為構成殺人罪未遂", "甲的行為構成重傷罪未遂", "甲的行為構成傷害未遂", "無罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00070', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '下列何種情形，甲該當刑法第315條之1之竊聽竊錄罪？', '["一對情侶在公園長椅上有親暱、愛撫舉動，甲行經該處竟以手機拍攝", "甲見鄰居乙年輕貌美，利用地利之便，從門縫偷看乙之日常生活", "甲妻懷疑乙夫有外遇，乃購得密錄器裝設於乙的自用小客車上，竊錄乙之車內言論及活動", "甲以蒐集女子小腿的照片為樂，常以高性能相機拍攝路上女子衣著未遮蔽的小腿部位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00071', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '刑法第271條第1項殺人罪法律效果為「死刑、無期徒刑或10年以上有期徒刑」、第320條第1 項竊盜罪法律效果為「5年以下有期徒刑、拘役或50萬元以下罰金」、第325條第1項搶奪罪法 律效果為「6月以上5年以下有期徒刑」及第354條毀損罪法律效果為「2年以下有期徒刑、拘役 或1萬5000元以下罰金」，有關刑度輕重之比較，下列敘述何者錯誤？', '["殺人罪重於搶奪罪", "搶奪罪重於竊盜罪", "竊盜罪重於毀損罪", "搶奪罪與竊盜罪一樣重"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00072', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '行為人所實施之一行為，因法規之錯綜關係，同時有數法條可以適用，由法官就數個條文中，擇 其最適當之一個規定適用，而排除其他法條，下列敘述何者正確？', '["想像競合", "法規競合", "數罪併罰", "裁判上一罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00073', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '關於刑罰之減輕，下列敘述何者錯誤？', '["死刑減輕者，為無期徒刑", "無期徒刑減輕者，為20年以下15年以上有期徒刑", "無免除其刑之規定時，有期徒刑減輕者，減輕其刑至二分之一", "無免除其刑之規定時，罰金減輕者，得減輕其刑至三分之二"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00074', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲欲購買砒霜毒死Ａ，但購買時老闆錯拿砂糖給甲，甲將買得之「毒藥」摻入飲料供Ａ飲用，A 飲用完覺得肚子疼痛。甲之刑責為何？', '["甲構成殺人罪之不能未遂", "甲構成殺人罪之中止未遂", "甲構成殺人罪之障礙未遂", "甲構成殺人罪之失敗未遂"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00075', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '有關假釋的敘述，下列何者正確？', '["假釋中因故意或過失更為犯罪，而受有期徒刑以上刑之宣告者，應撤銷假釋", "無期徒刑不得假釋", "在有期徒刑所餘刑期內未被撤銷假釋者，其未執行之刑，以已執行論", "有期徒刑執行逾二分之一，且執行已滿三個月以上者，應予假釋"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00076', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '有關保安處分的敘述，下列何者錯誤？', '["非拘束人身自由之保安處分，並無罪刑法定原則之適用", "保安處分僅得於裁判時一併宣告", "保安處分多採不定期制度", "保安處分不以罪責原則為基礎"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00077', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '對於收賄罪的敘述，下列何者錯誤？', '["收取賄賂與職務行為要具備對價關係", "職務上的行為，指的是公務員在其職務範圍內所應為或得為之行為", "收賄者與行賄之人共同成立收賄罪", "公務員就職務上之行為，允諾他人行求之款項，他人雖未交付，亦成立職務上收賄罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00078', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '依通說與實務見解，關於刑法第135條妨害公務執行罪，下列何者錯誤？', '["本罪之保護法益為國家公務，而非執行公務的公務員", "本罪為舉動犯", "依照實務見解，必須要直接對公務員之身體實施暴力，才能構成刑法第135條第1項之「強暴」", "以私行拘禁的方式妨害公務執行時，依照實務見解，兩罪應構成想像競合從一重處斷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL)
